import classNames from "classnames";
import { Link } from "gatsby";
import * as React from "react";

export default function Button({
  className,
  as = "anchor",
  type = "button",
  size = "md",
  href = "#",
  fill = true,
  disabled = false,
  onClick,
  children,
}) {
  const isInternalLink = href.startsWith("/") && !href.startsWith("//");

  const commonClasses = classNames(
    "inline-block rounded-lg border-2 text-center transition-[background,color]",

    size === "sm" && "px-4 py-2",
    size === "md" && "px-5 py-2.5",

    fill && "border-transparent bg-white text-black",
    !fill && "border-white bg-black text-white hover:bg-white hover:text-black",

    as === "anchor" && "hover:brightness-90",
    as === "button" && "enabled:hover:brightness-90",
    "disabled:cursor-not-allowed disabled:brightness-50",

    className,
  );

  if (as === "anchor") {
    if (isInternalLink) {
      return (
        <Link to={href} className={commonClasses}>
          {children}
        </Link>
      );
    } else {
      return (
        <a
          className={commonClasses}
          href={href}
          target="_blank"
          rel="noopener noreferrer"
        >
          {children}
        </a>
      );
    }
  }

  return (
    <button
      type={type}
      className={commonClasses}
      disabled={disabled}
      onClick={onClick}
    >
      {children}
    </button>
  );
}
